import React from 'react';

const ResultPage = ({ result, teamInfo, onRestart }) => {
  const { score, totalQuestions, timeTaken } = result;

  const formatTime = (microseconds) => {
    const seconds = Math.floor(microseconds / 1_000_000);
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes}m ${remainingSeconds}s`;
  };

  const percentage = Math.round((score / totalQuestions) * 100);

  const getMessage = () => {
    if (percentage >= 80) return 'Excellent work!';
    if (percentage >= 60) return 'Good job!';
    if (percentage >= 40) return 'Nice try!';
    return 'Better luck next time!';
  };

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      backgroundColor: '#ffffff'
    }}>
      <div style={{
        width: '100%',
        maxWidth: '450px',
        padding: '30px',
        textAlign: 'center'
      }}>
        <h1 style={{ 
          fontSize: '36px', 
          marginBottom: '10px', 
          color: '#1a202c',
          fontWeight: '700',
          letterSpacing: '-0.5px'
        }}>
          Quiz Complete!
        </h1>

        <p style={{ 
          color: '#4a5568', 
          marginBottom: '30px', 
          fontSize: '18px',
          fontWeight: '500'
        }}>
          {teamInfo.teamName}
        </p>

        <div style={{ 
          backgroundColor: '#f7fafc',
          padding: '30px',
          borderRadius: '12px',
          marginBottom: '30px',
          border: '1px solid #e2e8f0'
        }}>
          <div style={{ 
            fontSize: '56px', 
            fontWeight: '700', 
            color: '#1a202c',
            marginBottom: '10px',
            lineHeight: '1.2'
          }}>
            {score}/{totalQuestions}
          </div>

          <div style={{ 
            fontSize: '20px', 
            color: '#2d3748',
            marginBottom: '15px',
            fontWeight: '600'
          }}>
            {percentage}%
          </div>

          <div style={{ 
            fontSize: '18px', 
            color: '#4a5568',
            marginBottom: '20px'
          }}>
            {getMessage()}
          </div>

          <div style={{ 
            fontSize: '16px', 
            color: '#718096',
            padding: '10px',
            backgroundColor: '#ffffff',
            borderRadius: '8px',
            border: '1px solid #e2e8f0'
          }}>
            Time taken: {formatTime(timeTaken)}
          </div>
        </div>

        <button
          onClick={onRestart}
          style={{
            padding: '14px 36px',
            backgroundColor: '#1a202c',
            color: 'white',
            border: 'none',
            borderRadius: '8px',
            fontSize: '17px',
            fontWeight: '600',
            cursor: 'pointer',
            transition: 'background-color 0.2s'
          }}
          onMouseEnter={(e) => e.target.style.backgroundColor = '#2d3748'}
          onMouseLeave={(e) => e.target.style.backgroundColor = '#1a202c'}
        >
          Take Another Quiz
        </button>
      </div>
    </div>
  );
};

export default ResultPage;
